import{_ as a,o as r,c as t,a5 as o}from"./chunks/framework.CaodWED9.js";const u=JSON.parse('{"title":"kcp sharding in Platform Mesh","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/sharding.md","filePath":"reference/components/sharding.md"}'),s={name:"reference/components/sharding.md"};function i(l,e,n,h,d,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="kcp-sharding-in-platform-mesh" tabindex="-1">kcp sharding in Platform Mesh <a class="header-anchor" href="#kcp-sharding-in-platform-mesh" aria-label="Permalink to &quot;kcp sharding in Platform Mesh&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Sharding is a kcp configuration mode that distributes workspaces across multiple shards for horizontal scale. Platform Mesh supports sharded local setups and sharded production deployments.</p><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>A sharded Platform Mesh deployment runs multiple kcp shards behind the front proxy. Workspace state is partitioned across shards while the API surface remains a single endpoint to clients. The Platform Mesh operator and account-operator are aware of the sharded topology and reconcile state across shards.</p><h2 id="related-epic-task" tabindex="-1">Related epic task <a class="header-anchor" href="#related-epic-task" aria-label="Permalink to &quot;Related epic task&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/backlog/issues/249" target="_blank" rel="noreferrer">platform-mesh/backlog#249</a></li></ul><h2 id="future-reference" tabindex="-1">Future reference <a class="header-anchor" href="#future-reference" aria-label="Permalink to &quot;Future reference&quot;">​</a></h2><p>Add the local-setup sharded topology, shard membership and discovery, cross-shard workspace addressing, operational guidance for adding or removing shards, and any Platform Mesh-specific behavior that differs from upstream kcp sharding.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./kcp.html">kcp</a></li><li><a href="/pr-preview/pr-127/concepts/architecture.html">Architecture</a></li><li><a href="/pr-preview/pr-127/how-to-guides/set-up-platform-mesh-locally.html">Set up Platform Mesh locally</a></li></ul>',11)])])}const m=a(s,[["render",i]]);export{u as __pageData,m as default};
